const items = $input.all();

// ----------------------
// SAFE HELPER
// ----------------------
const safe = (v) =>
  Array.isArray(v) ? v.join(" ") : (v ?? "");

// ----------------------
// COPING MAP
// ----------------------
const copingMap = {
  skip: "skip_days",
  skip_days: "skip_days",
  reduce_meals: "reduce_meals",
  borrow_food: "borrow_food",
  sell_asserts: "sell_assets",
  sell_assets: "sell_assets"
};

// ----------------------
// PROCESS ALL ITEMS
// ----------------------
return items.map(({ json: data }) => {

  let gpsRaw = safe(data["gps_location"] || data["_geolocation"]);
  const gpsParts = gpsRaw ? gpsRaw.split(" ") : [];

  const copingRaw = safe(data["coping/coping_001"]).toLowerCase();
  const coping_strategy = copingMap[copingRaw] || copingRaw;

  return {
    json: {
      // CORE
      name: safe(data["household_info/respondent_name"]),
      age: Number(data["demographics/age"] || 0),
      gender: safe(data["demographics/gender"]),
      income: Number(data["economic/monthly_income"] || 0),
      household_size: Number(data["household_info/household_size"] || 0),

      // FOOD
      meals_skipped: Number(data["food_security/meals_skipped"] || 0),
      food_source: safe(data["food_security/food_source"]),

      // COPING
      coping_strategy,

      // WATER
      water_source: safe(data["water/water_source"]),
      water_time: Number(data["water/water_time"] || 0),

      // FIELD
      enumerator_name: safe(data["enumerator_name"]),
      gps_location_raw: gpsRaw,
      latitude: Number(gpsParts[0] || 0),
      longitude: Number(gpsParts[1] || 0),
      altitude: Number(gpsParts[2] || 0),
      accuracy: Number(gpsParts[3] || 0),
      consent: safe(data["consent_section/consent"]),
      date: safe(data["date"]),

      // META
      kobo_id: data["_id"] || "",
      uuid: data["_uuid"] || "",
      instance_id: data["meta/instanceID"] || "",
      submitted_by: data["_submitted_by"] || "",
      submission_time: data["_submission_time"] || ""
    }
  };
});

const items = $input.all();

const safe = (v) =>
  v === null || v === undefined ? "" : String(v).toLowerCase().trim();

const num = (v) => {
  const n = Number(v);
  return isNaN(n) ? 0 : n;
};

return items.map(({ json }) => {

  let score = 0;

  const income = num(json["economic/monthly_income"]);
  const meals = num(json["food_security/meals_skipped"]);
  const waterTime = num(json["water/water_time"]);

  const coping = safe(json["coping/coping_001"]);
  const food = safe(json["food_security/food_source"]);
  const water = safe(json["water/water_source"]);
  const employment = safe(json["economic/employment_status"]);

  // ----------------------
  // SCORING
  // ----------------------
  if (income <= 3000) score += 4;
  else if (income < 5000) score += 3;
  else if (income < 10000) score += 2;
  else if (income < 20000) score += 1;

  if (coping.includes("skip") || coping.includes("reduce")) score += 3;

  if (food.includes("aid") || food.includes("borrowing")) score += 3;

  if (meals >= 5) score += 4;
  else if (meals >= 3) score += 3;
  else if (meals >= 1) score += 1;

  if (waterTime > 180) score += 3;
  else if (waterTime > 120) score += 2;
  else if (waterTime > 60) score += 1;

  if (water.includes("river") || water.includes("dam") || water.includes("pond")) {
    score += 1;
  }

  if (employment.includes("unemployed") || employment.includes("casual")) {
    score += 1;
  }

  if (score > 10) score = 10;

  let classification = "Food Secure";
  if (score >= 8) classification = "Severe Insecurity";
  else if (score >= 5) classification = "Moderate Risk";

  return {
    json: {
      ...json,
      food_security_score: score,
      food_security_class: classification,
      scored_at: new Date().toISOString()
    }
  };
});

const results = $json.results || [];

return results.map(r => ({
  json: r
}));
